sysauto_script.script:
(function execute() {

    var today = new GlideDate();
    var thirtyDaysLater = new GlideDate();
    thirtyDaysLater.setValue(gs.daysAgo(-30)); //add 30 days from today

    var gr = new GlideRecord('x_1971078_smart_0_medicine_inventory'); 
    gr.addActiveQuery(); 
    gr.query();

    while (gr.next()) {
        var expDate = gr.getValue('expiration_date');
        if (!expDate) continue; // Skip if no expiration date is set

        var expGlide = new GlideDate();
        expGlide.setValue(expDate);

        // Check if expiration date is in the past
        if (expGlide.compareTo(today) < 0) {
            gr.status = 'expired';
            gr.update();
            gs.eventQueue('x_1971078_smart_0.pharmacy.expiry_alert', gr, 'expired', expDate);
        } 
        // Check if expiration date is within the next 30 days (including today)
        else if (expGlide.compareTo(thirtyDaysLater) <= 0) {
            gr.status = 'near expiry';
            gr.update();
            gs.eventQueue('x_1971078_smart_0.pharmacy.expiry_alert', gr, 'near expiry', expDate);
        }
    }
})();
